var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_CODEX_SPECIAL_NULL","text":{"KOREA":"우후후, 이런 계약서를 써서라도 날 붙잡아두고 싶다니. 달링은 내가 정말 필요한가보구나?","JPN":"うふふ、こんな契約書を書いてでも私をそばに置きたいなんて。ダーリンは本当に私のことが必要みたいだね。","ENG":"Fu fuu fuu. Seeing how you're trying to make excuses to keep me around by making me sign a contract. You must really need me, darling.","TWN":"呵呵呵，竟然想用一紙薄薄的契約把我留下，看來達令真的很需要我呢！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_SPECIAL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_CODEX_SPECIAL_NULL","text":{"KOREA":"그치만 난 언젠가 떠나야 해. 얼른 어엿한 대천사로 성장해서 할머니 대신 천상을 책임져야 하거든. 그렇죠, 스승님?","JPN":"でも、私はいつか帰らなきゃ。早く立派な大天使に成長して、お婆ちゃんの代わりに天上界を治めなければならないの。ね？　師匠。","ENG":"But I will have to leave one day. I need to become a respectable archangel and take care of heaven instead of Grandma. Isn't that right, Master?","TWN":"但是，我總有一天要離開。我必須快點成長為一名出色的大天使，代替奶奶管理天堂，對吧，師父？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_SPECIAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIRD_CODEX_SPECIAL_NULL","text":{"KOREA":"*꾸짖는 지저귐*","JPN":"*叱るさえずり*","ENG":"*Scolding chirps*"},"stage":{"bg":"SKY","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIRD_CODEX_SPECIAL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"VOICE_UNIT_CA_STREGA_YOO_NA_SPECIAL_BATTLE_PASSIVE_2"},{"id":"L12_1","type":"dialog","speaker":"YOONA_CODEX_SPECIAL_NULL","text":{"KOREA":"네? 저 같은 철부지 천사는 어엿한 대천사가 되려면 이백 년도 부족할 거라고요?","JPN":"えっ？　私のような世間知らずの天使が立派な大天使になるには、200年経っても足りない？","ENG":"Huh? It'll take at least two hundred years for an immature archangel like me to grow up?","TWN":"什麼？像我這樣不懂事的天使，要想成為出色的大天使，修練個二百年都還不夠嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_SPECIAL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOONA_CODEX_SPECIAL_NULL","text":{"KOREA":"오오, 잘 됐다! 그럼 달링이랑 이백 년은 같이 더 지낼 수 있는 거네요?","JPN":"おお、よかった！　じゃあ、ダーリンと200年は一緒にいられるわけですね？","ENG":"Ooh! That's wonderful! That means I can stay with you for another two centuries, right?","TWN":"哇喔，太好啦！那我就可以再跟達令多相處二百年咧？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_SPECIAL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_CODEX_SPECIAL_NULL","text":{"KOREA":"응? 이백 년이나 더 살아있을 자신이 없다고? 달링은 무슨 큰 병에라도 걸린 거야?","JPN":"うん？　200年も生きていられる自信がない？　ダーリンって、重病にでもかかってるの？","ENG":"Hmm? You're not sure if you can live another two hundred years? Are you sick? Is there something wrong with you, darling?","TWN":"嗯？你不確定能不能再多活二百年嗎？達令你是得到什麼不治之症嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_SPECIAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOONA_CODEX_SPECIAL_NULL","text":{"KOREA":"아무리 몸이 나빠도 그런 부정적인 말을 하는 건 좋지 않아!","JPN":"いくら体調が悪くても、そんな否定的な言葉を口にするのは良くないよ！","ENG":"Even if you aren't feeling well, it's not good to say such negative things!","TWN":"但就算身體不好，也不能說這種消極負面的話呀！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_SPECIAL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_CODEX_SPECIAL_NULL","text":{"KOREA":"내가 지상에서 지내는 동안 달링이 인간세계에 대해 많이 가르쳐 주기로 약속한 거, 벌써 잊은 건 아니지?","JPN":"私が地上にいる間はダーリンが人間世界についていっぱい教えてくれるって約束したの、忘れてないよね？","ENG":"You haven't forgotten your promise to teach me all about the human world while I'm down here, did you, darling?","TWN":"你沒忘記吧？你不是答應過我，我在地上的這段時間，你會教我一切有關人類世界的事？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_SPECIAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOONA_CODEX_SPECIAL_NULL","text":{"KOREA":"후후, 달링은 내가 책임질 테니 너무 걱정하지 마.","JPN":"ふふ、ダーリンのことは私が世話してあげるから、あまり心配しないで。","ENG":"Fu fuu. I'll also take care of you, so don't worry, darling.","TWN":"呵呵，放心，我也會對達令負責的。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_SPECIAL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_CODEX_SPECIAL_NULL","text":{"KOREA":"이 견습 대천사님의 축복이 담긴 특제 건강민트차를 매일 한 잔씩 마시면 괜찮을 거란 말씀!","JPN":"この見習い大天使の祝福が込められた特製ヘルシーミントティーを毎日一杯ずつ飲むとよくなるってこと！","ENG":"You'll be all right after you drink this archangel-in-training's super-healthy blessed mint tea every day!","TWN":"每天喝一杯我這個實習大天使特製的健康薄荷茶，包你每天平平安安！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_SPECIAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOONA_CODEX_SPECIAL_NULL","text":{"KOREA":"그리고 내가 대천사가 되는 날, 달링을 직접 천상으로 에스코트해 줄게!","JPN":"それに私が大天使になったら、ダーリンを直接天上界までエスコートしてあげる！","ENG":"And the day that I do become an archangel, I'll escort you myself to heaven!","TWN":"而且等我成為大天使的那一天，我會親自護送你到天堂！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_SPECIAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOONA_CODEX_SPECIAL_NULL","text":{"KOREA":"그러니까, 그때까지 아프지 않기로 나랑 약속! 대천사 도장 꾸욱!","JPN":"だからその時まで元気でいるって私と約束して！　大天使ハンコ、ギューッと！","ENG":"So, promise me you won't get sick until then! Cross your heart and hope to die!","TWN":"所以答應我，在那之前都不許生病！跟大天使打勾勾！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_SPECIAL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};